public class Car {
  String model = "Bilinmir";

  // Standart konstruktor (Java tərəfindən avtomatik təmin edilir, əgər başqa konstruktor yoxdursa)
  public Car() {
    // Boş konstruktor
  }

  void display() {
    System.out.println("Model: " + model);
  }

  public static void main(String[] args) {
    Car car = new Car();
    car.display();
  }
}
// Çıxış: Model: Bilinmir

public class Student {
  String name;
  int age;

  public Student(String name, int age) {
    this.name = name;
    this.age = age;
  }

  void displayInfo() {
    System.out.println("Ad: " + name + ", Yaş: " + age);
  }

  public static void main(String[] args) {
    Student student = new Student("Aysel", 20);
    student.displayInfo();
  }
}
// Çıxış: Ad: Aysel, Yaş: 20

public class Book {
  String title;
  int pages;

  // Parametrsiz konstruktor
  public Book() {
    title = "Naməlum";
    pages = 0;
  }

  // Parametrləşdirilmiş konstruktor
  public Book(String title, int pages) {
    this.title = title;
    this.pages = pages;
  }

  void display() {
    System.out.println("Kitab: " + title + ", Səhifələr: " + pages);
  }

  public static void main(String[] args) {
    Book book1 = new Book();
    Book book2 = new Book("Java Kitabı", 300);
    book1.display();
    book2.display();
  }
}
// Çıxış:
// Kitab: Naməlum, Səhifələr: 0
// Kitab: Java Kitabı, Səhifələr: 300

