public class Product {
  String name;
  double price;

  public Product() {
    this("Naməlum", 0.0); // Parametrləşdirilmiş konstruktoru çağırır
  }

  public Product(String name, double price) {
    this.name = name;
    this.price = price;
  }

  void displayProduct() {
    System.out.println("Məhsul: " + name + ", Qiymət: " + price + " AZN");
  }

  public static void main(String[] args) {
    Product product1 = new Product();
    Product product2 = new Product("Telefon", 599.99);
    product1.displayProduct();
    product2.displayProduct();
  }
}
// Çıxış:
// Məhsul: Naməlum, Qiymət: 0.0 AZN
// Məhsul: Telefon, Qiymət: 599.99 AZN

