public class Book {
  String title;
  int pages;

  // Parameterless constructor
  public Book() {
    title = "Unknown";
    pages = 0;
  }

  // Parameterized constructor
  public Book(String title, int pages) {
    this.title = title;
    this.pages = pages;
  }

  void display() {
    System.out.println("Book: " + title + ", Pages: " + pages);
  }

  public static void main(String[] args) {
    Book book1 = new Book();
    Book book2 = new Book("Java Book", 300);
    book1.display();
    book2.display();
  }
}
// Output:
// Book: Unknown, Pages: 0
// Book: Java Book, Pages: 300

